document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("selectedYear");e&&(e.innerHTML='<span class="header-app-style-other">Χρήση : </span>',setTimeout(()=>{(async()=>{try{const t=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,n=await fetch("/api/yearInUse",{method:"GET",headers:{"Content-Type":"application/json",...t&&{"CSRF-Token":t}},credentials:"include"});if(401===n.status)return void(e.innerHTML='<span class="header-app-style-other">Χρήση : </span>');if(!n.ok)throw new Error(`HTTP ${n.status}: ${n.statusText}`);const a=n.headers.get("content-type");if(!a||!a.includes("application/json"))return;const s=await n.text();if(!s||""===s.trim())return;const r=JSON.parse(s);r&&r.yearInUse?e.innerHTML=`<span class="header-app-style-other">Χρήση : ${r.yearInUse}</span>`:e.innerHTML='<span class="header-app-style-other">Χρήση : </span>'}catch(t){console.error("Πρόβλημα κατά την εμφάνιση του έτους χρήσης:",t),e.innerHTML='<span class="header-app-style-other">Χρήση : </span>'}})()},100))});